  dpia_required: isUnexpected
}}];

// GEOFENCE BREACH v3.0 — ZKLP verified zone violation
const d = $input.first().json;
const locale = d.parent_locale || 'en';
const isUnexpected = d.is_after_dark || (d.is_school_hours && !d.is_weekend);

const GEOFENCE_MSG = {
  sw: `🚨 *${d.child_name} amevuka mpaka!*
📍 Eneo: ${d.geofence_zone_name || 'Haijulikani'}
⏰ ${d.eat_time_str} EAT
🛡️ ZKLP: ${d._privacy.zklp_status}
🔐 Zone: ${d._privacy.zone_hash.substring(0,16)}...

*Hatua:*
1. Angalia ramani
2. Piga simu mtoto
3. Wasiliana na shule${isUnexpected ? '
4. **DHARURA — muda wa shule**' : ''}

_Mlinzi v3.0 | PQC-Secured_`,
  en: `🚨 *${d.child_name} breached safety zone!*
📍 Zone: ${d.geofence_zone_name || 'Unknown'}
⏰ ${d.eat_time_str} EAT
🛡️ ZKLP: ${d._privacy.zklp_status}
🔐 Zone: ${d._privacy.zone_hash.substring(0,16)}...

*Actions:*
1. Check secure map
2. Call child on device
3. Contact school${isUnexpected ? '
4. **EMERGENCY — school hours**' : ''}

_Mlinzi v3.0 | PQC-Secured_`
};

return [{ json: {
  ...d, whatsapp_message: GEOFENCE_MSG[locale] || GEOFENCE_MSG.en,
  notification_type: 'GEOFENCE_BREACH',
  ai_verdict: isUnexpected ? 'ESCALATE_AUTHORITIES' : 'ALERT_PARENT',
  send_to_parent: true, send_to_school: true, send_to_authorities: isUnexpected,
  requires_human_approval: isUnexpected, approval_timeout_minutes: 3,
  threshold_signatures_needed: isUnexpected ? 3 : 1,
  blockchain_memo: `GEOFENCE:${d.geofence_status}:${d.eat_time_str}`,
  dpia_required: true, dpia_category: 'High-risk child tracking'
}}];

