- DP: ε={{ $json._privacy.differential_privacy_epsilon }}
- ZKLP: {{ $json._privacy.zklp_status }}
- EAT Time: {{ $json.eat_time_str }} | Day: {{ $json.eat_day }}
- School hours: {{ $json.is_school_hours }} | After dark: {{ $json.is_after_dark }}
